create table clients (id int primary key, reference_client varchar(50), nom_entreprise varchar(50), compte_client_PROGRAMME_DE_FIDELITE_CLIENTS double, compte_client_AVANCE_DE_CASH double, compte_client double NOT NULL, dette_maximale_compte_client double NOT NULL, nom_representant varchar(50), description_client TEXT, localisation varchar(50), quartier varchar(50), ville varchar(50), province_etat varchar(50), pays varchar(50), boite_postale varchar(50), siege_social varchar(50), email varchar(50), numero_telephone_1 varchar(28), numero_telephone_2 varchar(28), reference_registre_du_commerce varchar(256), numero_contribuable varchar(256), refereur_client varchar(50), refereur_client_ID int, groupes_du_client varchar(3000), groupes_du_client_ID varchar(5000), client_prochain_rendez_vous date, image_compte_client mediumblob);
